// In template: <div :ref="rootEl">
// In script:
console.log(rootEl.el)    // HTMLDivElement | null
console.log(rootEl.value) // same ref target

import { themeSelector } from 'origam'

themeSelector({ name: '', mode: 'auto' })
// → ':root'

themeSelector({ name: 'brand-x', mode: 'auto' })
// → '[data-theme="brand-x"]'

themeSelector({ name: 'brand-x', mode: 'dark' })
// → '[data-theme="brand-x"][data-mode="dark"]'

returns.description_fallback:
A CSS rule string of the form `<selector> {
  --origam-…: value;
  …
}
`. Empty when the resolved token map is empty.

examples.code:
import { themeToCss } from 'origam'

const css = themeToCss({
  name: 'brand-x',
  mode: 'auto',
  cssVars: {
    '--origam-color__action--primary---bg': '#0057ff',
    '--origam-color__action--primary---fg': '#ffffff',
  },
})
// → '[data-theme="brand-x"] {\n  --origam-color__action--primary---bg: #0057ff;\n  …\n}\n'

import { themeVarsToVars } from 'origam'

const flat = themeVarsToVars({
  color: {
    'action-primary-bg': '#0057ff',
    'action-primary-fg': '#ffffff',
  },
})
// → {
//   '--origam-color---action-primary-bg': '#0057ff',
//   '--origam-color---action-primary-fg': '#ffffff',
// }

import { toISO, useDateAdapter } from 'origam'

const { adapter } = useDateAdapter()
toISO(adapter, new Date('2024-06-01'))
// → '2024-06-01'

import { tokenForegroundForIntent } from 'origam'

tokenForegroundForIntent('primary')
// → 'var(--origam-color__action--primary---fgSubtle)'

tokenForegroundForIntent('danger')
// → 'var(--origam-color__feedback--danger---fgSubtle)'

tokenForegroundForIntent('neutral')
// → 'var(--origam-color__action--secondary---fg)'

import { tokenPathToCssVar } from 'origam'

tokenPathToCssVar(['btn', 'primary', 'background-color'], true)
// → '--origam-btn--primary---background-color'

tokenPathToCssVar(['color', 'neutral', '500'], false)
// → '--origam-color__neutral---500'

import { tokenPathToCssVarName } from 'origam'

// Component token — simple property
tokenPathToCssVarName(['btn', 'background-color'], true)
// → 'origam-btn---background-color'

// Component token — state variant
tokenPathToCssVarName(['btn', 'primary', 'background-color'], true)
// → 'origam-btn--primary---background-color'

// Semantic token (2-level)
tokenPathToCssVarName(['color', 'primary'], false)
// → 'origam-color---primary'

import { tokenStylesForIntent } from 'origam'

tokenStylesForIntent('primary')
// → { 'background-color': 'var(--origam-color__action--primary---bg)',
//      color: 'var(--origam-color__action--primary---fg)' }

tokenStylesForIntent('danger', 'hover')
// → { 'background-color': 'var(--origam-color__feedback--danger--hover---bg)',
//      color: 'var(--origam-color__feedback--danger--hover---fg)' }

import { transformDataTableItem } from 'origam'

const item = { id: 1, name: 'Alice', role: 'admin' }
const columns = [
  { key: 'name', value: 'name' },
  { key: 'role', value: 'role' },
]

const row = transformDataTableItem(
  { itemValue: 'id', itemSelectable: undefined, returnObject: false },
  item,
  0,
  columns
)
// row.value → 1
// row.columns → { name: 'Alice', role: 'admin' }

import { transformDataTableItems } from 'origam'

const rows = transformDataTableItems(
  { itemValue: 'id', itemSelectable: undefined, returnObject: false },
  [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ],
  [{ key: 'name', value: 'name' }]
)
// rows[0].value → 1
// rows[0].columns → { name: 'Alice' }

import { transformListItem } from 'origam'

const item = transformListItem(
  { itemTitle: 'label', itemValue: 'id', itemChildren: 'children', itemProps: false },
  { id: 42, label: 'Settings', children: [] }
)
// item.title  → 'Settings'
// item.value  → 42
// item.children → []

import { transformListItems } from 'origam'

const items = transformListItems(
  { itemTitle: 'name', itemValue: 'id', itemChildren: 'children', itemProps: false },
  [
    { id: 1, name: 'Home' },
    { id: 2, name: 'Settings' },
  ]
)
// items[0].title → 'Home'
// items[0].value → 1

import { tryOnMounted } from 'origam'

// Inside a composable used in <script setup>:
// → registers with onMounted normally
tryOnMounted(() => console.log('mounted'))

// Inside a utility called in a test or SSR context
// (no current Vue instance):
// → executes synchronously right away
tryOnMounted(() => console.log('no instance, runs now'))

// Deferred in the nextTick when outside a component:
tryOnMounted(() => console.log('next tick'), false)

import { tryOnScopeDispose } from 'origam'

// Inside a component / composable — registered normally
const registered = tryOnScopeDispose(() => {
    clearInterval(timer)
})
// registered → true

// Outside any Vue scope — silently skipped
const skipped = tryOnScopeDispose(() => clearInterval(timer))
// skipped → false

import { bindProps, unbindProps } from 'origam'

const props = { onClick: handleClick, 'aria-label': 'Close' }

// Mount phase
bindProps(el, props)

// Unmount phase — removes listener and attribute
unbindProps(el, props)

import { unmountIntersect } from 'origam'

// Inside a custom directive using v-intersect internals
const myDirective = {
    unmounted(el, binding) {
        unmountIntersect(el, binding)
    },
}

import { ref, onMounted } from 'vue'
import { unrefElement } from 'origam'

const btnRef = ref(null)

onMounted(() => {
    const el = unrefElement(btnRef)
    // el → HTMLButtonElement
    el?.focus()
})

import { updateHover } from 'origam'

const vHover = {
    updated(el, binding) {
        const wasEnabled = el._hover?.enabled ?? false
        updateHover(el, binding, wasEnabled, 'my-component')
    },
}

import { updateRipple } from 'origam'

const vRipple = {
    updated(el, binding) {
        const wasEnabled = el._ripple?.enabled ?? false
        updateRipple(el, binding, wasEnabled)
    },
}

import { useProvided } from 'origam'

// In a component that accepts an optional locale prop:
const props = defineProps<{ locale?: string }>()
const { locale: injectedLocale } = useLocale()

const locale = useProvided(props, 'locale', injectedLocale)
// locale.value → props.locale if defined, else injectedLocale.value

import { viewportToElement } from 'origam'

el.addEventListener('click', (e) => {
    const box = el.getBoundingClientRect()
    const local = viewportToElement(
        { x: e.clientX, y: e.clientY },
        box
    )
    // local.x / local.y → position relative to el's top-left corner
})

import { warnLegacyColor } from 'origam'

// Triggers a console.warn on first call for this pair:
warnLegacyColor('bgColor', '#ff0080')

// Silent on second call — already warned:
warnLegacyColor('bgColor', '#ff0080')

